const body = $json.body || {};
const idempotencyKey = body.idempotencyKey || null;
const category = String(body.category || '').trim();
const ideaCount = Number(body.ideaCount || 1);
const workflowRunId = Number(body.workflowRunId || 0);
const topic = String(body.topic || '').trim().slice(0, 240) || null;
const durationTarget = ['short', 'medium', 'long'].includes(String(body.durationTarget || '').trim()) ? String(body.durationTarget).trim() : 'medium';
const rawLanguage = String(body.language || 'fr').trim().toLowerCase();
const languageMap = {
  fr: { code: 'fr', label: 'French', instruction: 'Write every user-facing field in natural French.' },
  en: { code: 'en', label: 'English', instruction: 'Write every user-facing field in natural English.' },
  es: { code: 'es', label: 'Spanish', instruction: 'Write every user-facing field in natural Spanish.' },
  it: { code: 'it', label: 'Italian', instruction: 'Write every user-facing field in natural Italian.' },
  de: { code: 'de', label: 'German', instruction: 'Write every user-facing field in natural German.' },
  ar: { code: 'ar', label: 'Modern Standard Arabic', instruction: 'Write every user-facing field in Modern Standard Arabic using Arabic script.' },
  ary: { code: 'ary', label: 'Moroccan Darija', instruction: 'Write every user-facing field in natural Moroccan Darija using Arabic script, with familiar Moroccan wording.' },
  darija: { code: 'ary', label: 'Moroccan Darija', instruction: 'Write every user-facing field in natural Moroccan Darija using Arabic script, with familiar Moroccan wording.' },
  ma: { code: 'ary', label: 'Moroccan Darija', instruction: 'Write every user-facing field in natural Moroccan Darija using Arabic script, with familiar Moroccan wording.' }
};
const language = languageMap[rawLanguage] || languageMap.fr;
const temperatureInput = Number(body.temperature);
const temperature = Number.isFinite(temperatureInput) ? Math.min(1.2, Math.max(0.1, temperatureInput)) : 0.7;
const inspirationRef = String(body.inspirationRef || '').trim().slice(0, 600) || null;
const sceneCountInput = Number(body.sceneCount || 1);
const sceneCount = Number.isInteger(sceneCountInput) ? Math.min(10, Math.max(1, sceneCountInput)) : 1;

if (!category) throw new Error('category is required');
if (!Number.isInteger(ideaCount) || ideaCount < 1 || ideaCount > 5) throw new Error('ideaCount must be 1-5');
if (!workflowRunId || workflowRunId <= 0) throw new Error('workflowRunId is required and must be > 0');

return [{ json: { idempotencyKey, category, ideaCount, workflowRunId, topic, durationTarget, language, temperature, inspirationRef, sceneCount, templateId: body.templateId || null, tiktokAccountOpenId: body.tiktokAccountOpenId || null } }];

const topic = String($json.choices?.[0]?.message?.content || '').trim().replace(/^[-*\d.)\s]+/, '').slice(0, 255);
if (!topic || topic.length < 5) throw new Error('LLM_IDEA_TOO_SHORT');
const input = $('Expand Ideas').item.json;
return [{ json: { topic, category: input.category, workflowRunId: input.workflowRunId, templateId: input.templateId, tiktokAccountOpenId: input.tiktokAccountOpenId, ideaIndex: input.ideaIndex, durationTarget: input.durationTarget, language: input.language, temperature: input.temperature, inspirationRef: input.inspirationRef, sceneCount: input.sceneCount } }];

const idea = $json.body || $json;
const contentIdeaId = Number(idea.id || 0);
if (!contentIdeaId || contentIdeaId <= 0) throw new Error('Backend did not return idea id');
const normalized = $('Normalize Idea').item.json;
const sceneCount = Number(normalized.sceneCount || 1);
const language = normalized.language || { label: 'French', instruction: 'Write every user-facing field in natural French.' };
const prompt = [
  'Language: ' + language.label,
  'Instruction: ' + language.instruction,
  'Category: ' + normalized.category,
  'Topic: ' + normalized.topic,
  'Duration target: ' + normalized.durationTarget,
  'Scene count: ' + sceneCount,
  normalized.inspirationRef ? 'Inspiration/reference to respect: ' + normalized.inspirationRef : '',
  '',
  'Generate a professional TikTok storyboard package. Every visible/user-facing value must be in the selected language: sceneText, script, caption, hook, hashtags. Do not mix French or English unless that language was selected.',
  'The scenes array MUST contain exactly ' + sceneCount + ' objects. Each scene is one short sentence and will become one row in the app.',
  'Each scene must also include a specific visualKeyword for Pexels, cameraMood, and overlayPriority.',
  'The script must be exactly the sceneText values joined in order.',
  'Caption should be 1-2 catchy phrases with 2-3 relevant hashtags in the selected language.',
  'Hook must be the first phrase people see in the first second.',
  'background_keyword must be the strongest visual search keyword.',
  'qualityReview must honestly score the package from 0 to 100 and list issues.',
  '',
  'Return exactly this JSON shape, with scenes containing exactly ' + sceneCount + ' objects:',
  '{"scenes":[{"sceneText":"...","visualKeyword":"...","cameraMood":"close-up dramatic","overlayPriority":"hook"}],"script":"...","caption":"...","hook":"...","background_keyword":"...","qualityReview":{"score":85,"issues":[],"languageOk":true,"sceneCountOk":true}}'
].filter((line) => line !== '').join('\n');
const groqScriptRequestBody = JSON.stringify({
  model: 'llama-3.3-70b-versatile',
  temperature: normalized.temperature,
  max_tokens: 1100,
  messages: [
    { role: 'system', content: 'You are a TikTok content director, scene planner, and QA reviewer. Return ONLY valid JSON without markdown. Follow requested counts exactly.' },
    { role: 'user', content: prompt }
  ]
});
return [{ json: { contentIdeaId, topic: normalized.topic, category: normalized.category, workflowRunId: normalized.workflowRunId, ideaIndex: normalized.ideaIndex, durationTarget: normalized.durationTarget, language, temperature: normalized.temperature, inspirationRef: normalized.inspirationRef, sceneCount, groqScriptRequestBody } }];

const http = require('http');
const https = require('https');
const { URL } = require('url');

const source = $('Extract Idea ID').item.json;
const expectedSceneCount = Math.min(10, Math.max(1, Number(source.sceneCount || 1)));
const selectedLanguage = source.language || { label: 'French', instruction: 'Write every user-facing field in natural French.' };

function stripMarkdown(raw) {
  return String(raw || '').trim().replace(/^```json\s*/i, '').replace(/^```/i, '').replace(/```$/i, '').trim();
}

function parsePackage(raw) {
  const cleaned = stripMarkdown(raw);
  try {
    return JSON.parse(cleaned);
  } catch (e) {
    throw new Error('LLM_SCRIPT_PARSE_ERROR: ' + e.message);
  }
}

function sentenceSplit(value) {
  return String(value || '')
    .split(/(?<=[.!??])\s+/)
    .map((scene) => scene.trim())
    .filter(Boolean);
}

function normalizeScene(scene, index) {
  const raw = scene && typeof scene === 'object' ? scene : { sceneText: scene };
  const sceneText = String(raw.sceneText || raw.text || raw.script || '').trim();
  return {
    sceneText,
    visualKeyword: String(raw.visualKeyword || raw.mediaQuery || raw.keyword || source.topic || source.category || 'professional').trim(),
    cameraMood: String(raw.cameraMood || raw.mood || raw.emotion || (index === 0 ? 'close-up dramatic' : 'dynamic vertical')).trim(),
    overlayPriority: String(raw.overlayPriority || raw.priority || (index === 0 ? 'hook' : 'body')).trim()
  };
}

function normalizePackage(parsed) {
  let scenes = Array.isArray(parsed.scenes)
    ? parsed.scenes.map(normalizeScene)
    : sentenceSplit(parsed.script).map((text, index) => normalizeScene({ sceneText: text }, index));
  scenes = scenes.filter((scene) => scene.sceneText.length > 0);
  const qualityReview = parsed.qualityReview && typeof parsed.qualityReview === 'object'
    ? parsed.qualityReview
    : { score: 0, issues: ['missing_quality_review'], languageOk: null, sceneCountOk: scenes.length === expectedSceneCount };
  return { ...parsed, scenes, qualityReview };
}

function sceneCountOk(pkg) {
  return Array.isArray(pkg.scenes) && pkg.scenes.length === expectedSceneCount;
}

function qaScore(pkg) {
  const score = Number(pkg.qualityReview?.score);
  return Number.isFinite(score) ? score : 0;
}

async function callGroqRepair(pkg, reason) {
  const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
  const secret = String($env.APP_VIDEO_OPS_INTERNAL_API_SECRET || '');
  if (!baseUrl || !secret) {
    throw new Error('LLM_REPAIR_CONFIG_MISSING');
  }
  const body = JSON.stringify({
    model: 'llama-3.3-70b-versatile',
    temperature: 0.35,
    max_tokens: 1100,
    messages: [
      { role: 'system', content: 'You are a strict TikTok storyboard QA and repair agent. Return ONLY valid JSON without markdown.' },
      { role: 'user', content: 'Repair this TikTok package. Reason: ' + reason + '\nLanguage: ' + selectedLanguage.label + '\nInstruction: ' + selectedLanguage.instruction + '\nExpected scene count: ' + expectedSceneCount + '\nTopic: ' + source.topic + '\nCategory: ' + source.category + '\n\nRules: scenes MUST contain exactly ' + expectedSceneCount + ' objects. Every visible field must be in the selected language. Keep sceneText punchy and short. Keep/add visualKeyword, cameraMood, overlayPriority. qualityReview.score must be >= 80 after repair. Return the exact same JSON shape.\n\nPackage to repair:\n' + JSON.stringify(pkg).slice(0, 5000) }
    ]
  });
  const url = new URL(baseUrl + '/api/video-ops/internal/groq/chat-completions');
  const client = url.protocol === 'https:' ? https : http;
  const response = await new Promise((resolve, reject) => {
    const req = client.request({
      protocol: url.protocol,
      hostname: url.hostname,
      port: url.port || (url.protocol === 'https:' ? 443 : 80),
      path: url.pathname + url.search,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body),
        'X-Video-Ops-Internal-Secret': secret
      }
    }, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => resolve({ statusCode: res.statusCode || 0, body: data }));
    });
    req.on('error', reject);
    req.setTimeout(30000, () => {
      req.destroy();
      reject(new Error('LLM_REPAIR_TIMEOUT'));
    });
    req.write(body);
    req.end();
  });
  if (response.statusCode < 200 || response.statusCode >= 300) {
    throw new Error('LLM_REPAIR_HTTP_' + response.statusCode + ': ' + String(response.body || '').slice(0, 200));
  }
  const json = JSON.parse(response.body);
  return parsePackage(json.choices?.[0]?.message?.content || '');
}

let pkg = normalizePackage(parsePackage($json.choices?.[0]?.message?.content || ''));
let repairReason = null;
if (!sceneCountOk(pkg)) repairReason = 'scene_count_mismatch expected ' + expectedSceneCount + ' got ' + pkg.scenes.length;
else if (qaScore(pkg) < 75) repairReason = 'qa_score_too_low ' + qaScore(pkg);

if (repairReason) {
  pkg = normalizePackage(await callGroqRepair(pkg, repairReason));
  pkg.qualityReview = { ...(pkg.qualityReview || {}), repaired: true, repairReason };
}

if (!sceneCountOk(pkg)) {
  throw new Error('LLM_SCENE_COUNT_MISMATCH_AFTER_REPAIR: expected ' + expectedSceneCount + ', got ' + pkg.scenes.length);
}
if (qaScore(pkg) < 70) {
  throw new Error('LLM_QA_SCORE_TOO_LOW_AFTER_REPAIR: ' + qaScore(pkg));
}

const normalizeSentence = (value) => {
  const text = String(value || '').trim();
  if (!text) return '';
  return /[.!??]$/.test(text) ? text : text + '.';
};
const script = pkg.scenes.map((scene) => normalizeSentence(scene.sceneText)).join(' ');
const backgroundKeyword = String(pkg.background_keyword || pkg.backgroundKeyword || pkg.scenes[0]?.visualKeyword || source.topic || '').trim();

if (!script) throw new Error('LLM_MISSING_FIELD: script');
if (!pkg.caption) throw new Error('LLM_MISSING_FIELD: caption');
if (!pkg.hook) throw new Error('LLM_MISSING_FIELD: hook');

return [{ json: {
  script,
  planned_scenes: JSON.stringify(pkg.scenes),
  generation_review: JSON.stringify(pkg.qualityReview || {}),
  scene_count: expectedSceneCount,
  caption: pkg.caption,
  hook: pkg.hook,
  background_keyword: backgroundKeyword,
  contentIdeaId: source.contentIdeaId,
  workflowRunId: source.workflowRunId
} }];

const items = $input.all();
const workflowRunId = Number($('Validate Input').first().json.workflowRunId || 0);
return [{ json: { workflowRunId, generatedCount: items.length, createdAt: new Date().toISOString() } }];

const http = require('http');
const https = require('https');
const { URL } = require('url');
const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const workflowRunId = Number($json.workflowRunId || 0);
const idempotencyKey = String($json.idempotencyKey || '').trim();

if (!baseUrl || !callbackSecret || !workflowRunId) {
  throw new Error('Missing callback config');
}

const body = JSON.stringify({
  status: 'SUCCEEDED',
  message: 'Idea and script generation complete.',
  responsePayload: JSON.stringify({ generatedCount: Number($json.generatedCount || 0) })
});

const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;

let response = null;
let lastError = null;
for (let attempt = 1; attempt <= 3; attempt++) {
  try {
    response = await new Promise((resolve, reject) => {
      const req = client.request({
        protocol: url.protocol,
        hostname: url.hostname,
        port: url.port || (url.protocol === 'https:' ? 443 : 80),
        path: url.pathname + url.search,
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(body),
          'X-Video-Ops-Callback-Secret': callbackSecret,
          ...(idempotencyKey ? { 'X-Idempotency-Key': idempotencyKey } : {})
        }
      }, (res) => {
        let data = '';
        res.on('data', (chunk) => { data += chunk; });
        res.on('end', () => resolve({ statusCode: res.statusCode || 0, body: data }));
      });

      req.on('error', reject);
      req.setTimeout(10000, () => {
        req.destroy();
        reject(new Error('Callback timeout'));
      });

      req.write(body);
      req.end();
    });

    if (response.statusCode >= 200 && response.statusCode < 300) break;
    if (response.statusCode === 409) throw new Error('CALLBACK_OBSOLETE_REPLAY: 409 idempotency mismatch');
    lastError = 'Callback failed: ' + response.statusCode;
  } catch (error) {
    lastError = error.message || String(error);
    if (attempt < 3) await new Promise(r => setTimeout(r, 500 * attempt));
    else throw error;
  }
}

if (!response || response.statusCode < 200 || response.statusCode >= 300) throw new Error(lastError);
return [{ json: { ok: true, workflowRunId, generatedCount: $json.generatedCount, callbackStatusCode: response.statusCode } }];

let error = 'Unknown error';
if (typeof $json === 'string') {
  error = $json;
} else if ($json && typeof $json === 'object') {
  error = $json.message || $json.error || $json.toString();
}

let contentIdeaId = 0;
try {
  const extractNode = $('Extract Idea ID');
  if (extractNode && extractNode.item && extractNode.item.json) {
    contentIdeaId = Number(extractNode.item.json.contentIdeaId || 0);
  }
} catch (e) {}

let workflowRunId = 0;
try {
  const validateNode = $('Validate Input');
  if (validateNode && validateNode.first() && validateNode.first().json) {
    workflowRunId = Number(validateNode.first().json.workflowRunId || 0);
  }
} catch (e) {}

let idempotencyKey = null;
try {
  const validateNode = $('Validate Input');
  if (validateNode && validateNode.first() && validateNode.first().json) {
    idempotencyKey = validateNode.first().json.idempotencyKey || null;
  }
} catch (e) {}

return [{ json: { idempotencyKey, contentIdeaId, workflowRunId, error: String(error).slice(0, 500), error_at: new Date().toISOString() } }];

const http = require('http');
const https = require('https');
const { URL } = require('url');
const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const workflowRunId = Number($json.workflowRunId || 0);
const idempotencyKey = String($json.idempotencyKey || '').trim();
const errorMsg = String($json.error || 'Unknown error');

if (!baseUrl || !callbackSecret || !workflowRunId) {
  return [{ json: { ok: false, error: errorMsg } }];
}

const body = JSON.stringify({
  status: 'FAILED',
  message: 'Generation failed: ' + errorMsg.slice(0, 200),
  responsePayload: JSON.stringify({ error: errorMsg.slice(0, 500) })
});

const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;

let response = null;
for (let attempt = 1; attempt <= 2; attempt++) {
  try {
    response = await new Promise((resolve) => {
      const req = client.request({
        protocol: url.protocol,
        hostname: url.hostname,
        port: url.port || (url.protocol === 'https:' ? 443 : 80),
        path: url.pathname + url.search,
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(body),
          'X-Video-Ops-Callback-Secret': callbackSecret,
          ...(idempotencyKey ? { 'X-Idempotency-Key': idempotencyKey } : {})
        }
      }, (res) => {
        res.on('data', () => {});
        res.on('end', () => resolve({ statusCode: res.statusCode || 0 }));
      });

      req.on('error', () => resolve({ statusCode: 0 }));
      req.setTimeout(10000, () => {
        req.destroy();
        resolve({ statusCode: 0 });
      });

      req.write(body);
      req.end();
    });
    if (response.statusCode >= 200 && response.statusCode < 300) break;
  } catch (e) {}
}

return [{ json: { ok: false, error: errorMsg, workflowRunId, callbackAttempted: true } }];
